  gender: ("male" | "female")[]
  experience: ("beginner" | "intermediate" | "advanced")[]
  progressionScheme: {
    type: "linear" | "periodized"
    deloadWeek: number
    progressionRules: {
      compound: {
        successThreshold: string
        weightIncrease: number
        failureResponse: string
      }
      isolation: {
        successThreshold: string
        weightIncrease: number
        failureResponse: string
      }
    }
  }
  schedule: {
    [key: string]: WorkoutDay
  }
}

