                value={endProgramConfirmation}
                onChange={(e) => setEndProgramConfirmation(e.target.value)}
              />
            </div>
            <DialogFooter>
              <Button
                variant="outline"
                onClick={() => {
                  setShowEndProgramDialog(false)
                  setEndProgramConfirmation("")
