            <DialogFooter>
              <Button variant="outline" onClick={() => setShowAddExerciseDialog(false)}>
                Cancel
              </Button>
              <Button disabled>Add Exercise</Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>

        <Dialog open={showEndProgramDialog} onOpenChange={setShowEndProgramDialog}>
          <DialogContent>
