                              onClick={() => handleAddSet(exercise.id, exercise.sets[exercise.sets.length - 1].id)}
                            >
                              <Plus className="h-4 w-4 mr-2" />
                              Add set
                            </DropdownMenuItem>
                            <DropdownMenuItem
                              onClick={() => handleSkipSet(exercise.id, exercise.sets[exercise.sets.length - 1].id)}
                            >
