                            <Input
                              type="number"
                              value={set.reps || ""}
                              onChange={(e) =>
                                handleSetUpdate(exercise.id, set.id, "reps", Number.parseInt(e.target.value) || 0)
                              }
                              className="text-center h-10 bg-muted/30 border-border/50"
                              placeholder=""
                            />
