                </Card>
              ))}
            </div>
          ))}

          <div className="lg:hidden pt-8 pb-24">
            {!isWorkoutBlocked && (
              <>
                {workout.completed ? (
                  <div className="w-full p-4 bg-green-50 border-2 border-green-500 rounded-lg text-center">
