  if (!workout || endProgramConfirmation !== "End Program") return

  const updatedWorkout = { ...workout }
  updatedWorkout.exercises.forEach((exercise) => {
    exercise.sets.forEach((set) => {
      if (!set.completed) {
        set.completed = true
        set.reps = 0
