}

export interface WorkoutSession {
  id: string
  userId: string
  programId?: string
  workoutName: string
  startTime: number
  endTime?: number
  exercises: WorkoutExercise[]
  notes?: string
  completed: boolean
  week?: number
  day?: number
}

export class WorkoutLogger {
  private static readonly STORAGE_KEY = "liftlog_workouts"
  private static readonly IN_PROGRESS_KEY = "liftlog_in_progress_workouts"

  static getInProgressWorkout(week: number, day: number): WorkoutSession | null {
    if (typeof window === "undefined") return null

    try {
      const stored = localStorage.getItem(this.IN_PROGRESS_KEY)
      if (!stored) return null

      const workouts: WorkoutSession[] = JSON.parse(stored)
      return workouts.find((w) => w.week === week && w.day === day) || null
    } catch {
      return null
    }
  }

  static getCurrentWorkout(): WorkoutSession | null {
    if (typeof window === "undefined") return null

    try {
      const activeProgram = typeof window !== "undefined" ? this.getActiveProgram() : null
      if (!activeProgram) return null

      return this.getInProgressWorkout(activeProgram.currentWeek, activeProgram.currentDay)
    } catch {
      return null
    }
  }

  private static getActiveProgram() {
    try {
      const stored = localStorage.getItem("liftlog_active_program")
      return stored ? JSON.parse(stored) : null
    } catch {
      return null
    }
  }

  static saveCurrentWorkout(workout: WorkoutSession): void {
    if (typeof window === "undefined") return
    if (!workout.week || !workout.day) return

    try {
      const stored = localStorage.getItem(this.IN_PROGRESS_KEY)
      let workouts: WorkoutSession[] = stored ? JSON.parse(stored) : []

      // Remove existing workout for this week/day
      workouts = workouts.filter((w) => !(w.week === workout.week && w.day === workout.day))

      // Add updated workout
      workouts.push(workout)

      localStorage.setItem(this.IN_PROGRESS_KEY, JSON.stringify(workouts))
    } catch (error) {
      console.error("Failed to save workout:", error)
    }
  }

  static clearCurrentWorkout(week?: number, day?: number): void {
    if (typeof window === "undefined") return

    try {
      if (week && day) {
        const stored = localStorage.getItem(this.IN_PROGRESS_KEY)
        if (!stored) return

        let workouts: WorkoutSession[] = JSON.parse(stored)
        workouts = workouts.filter((w) => !(w.week === week && w.day === day))
        localStorage.setItem(this.IN_PROGRESS_KEY, JSON.stringify(workouts))
      } else {
        // Clear all in-progress workouts
        localStorage.removeItem(this.IN_PROGRESS_KEY)
      }
    } catch (error) {
      console.error("Failed to clear workout:", error)
    }
  }

  static startWorkout(
    workoutName: string,
    exercises: {
      exerciseId: string
      exerciseName: string
      targetSets: number
      targetReps: string
      targetRest: string
      suggestedWeight?: number
      progressionNote?: string
    }[],
    week?: number,
    day?: number,
  ): WorkoutSession {
    if (week && day) {
      const existing = this.getInProgressWorkout(week, day)
      if (existing) {
        const isCorrupted =
          !existing.week || !existing.day || existing.exercises.some((ex) => !ex.sets || ex.sets.length === 0)

        if (isCorrupted) {
          console.log("[v0] Found corrupted workout data, clearing and creating fresh workout")
          this.clearCurrentWorkout(week, day)
          // Fall through to create new workout
        } else {
          console.log(
            "[v0] Found existing workout for week",
            week,
            "day",
            day,
            "with",
            existing.exercises.length,
            "exercises",
          )
          console.log("[v0] Workout structure:", {
            id: existing.id,
            exerciseCount: existing.exercises.length,
            exercises: existing.exercises.map((ex) => ({
              name: ex.exerciseName,
              setsCount: ex.sets?.length || 0,
              hasSets: !!ex.sets,
            })),
          })
          return existing
        }
      }
    }

    console.log("[v0] Creating new workout for week", week, "day", day)
    const workout: WorkoutSession = {
      id: Math.random().toString(36).substr(2, 9),
      userId: "current-user",
      workoutName,
      startTime: Date.now(),
      week,
      day,
      exercises: exercises.map((ex) => ({
        id: Math.random().toString(36).substr(2, 9),
        exerciseId: ex.exerciseId,
        exerciseName: ex.exerciseName,
        targetSets: ex.targetSets,
        targetReps: ex.targetReps,
        targetRest: ex.targetRest,
        sets: Array.from({ length: ex.targetSets }, (_, i) => ({
          id: Math.random().toString(36).substr(2, 9),
          reps: 0,
          weight: ex.suggestedWeight || 0, // Pre-fill with suggested weight from progression
          completed: false,
        })),
        completed: false,
      })),
      completed: false,
      notes: exercises.find((e) => e.progressionNote)?.progressionNote || "",
    }

    console.log("[v0] Created workout structure:", {
      id: workout.id,
      exerciseCount: workout.exercises.length,
      exercises: workout.exercises.map((ex) => ({
        name: ex.exerciseName,
        setsCount: ex.sets.length,
      })),
    })

    this.saveCurrentWorkout(workout)
    console.log("[v0] Saved workout to localStorage")
    return workout
  }

  static updateSet(
    workout: WorkoutSession,
    exerciseId: string,
    setId: string,
    updates: Partial<WorkoutSet>,
  ): WorkoutSession | null {
    const updatedWorkout = JSON.parse(JSON.stringify(workout)) as WorkoutSession

    const exercise = updatedWorkout.exercises.find((ex) => ex.id === exerciseId)
    if (!exercise) return null

    const set = exercise.sets.find((s) => s.id === setId)
    if (!set) return null

    Object.assign(set, updates)

    // Check if exercise is completed
    exercise.completed = exercise.sets.every((s) => s.completed)
    if (exercise.completed && !exercise.endTime) {
      exercise.endTime = Date.now()
    }

    this.saveCurrentWorkout(updatedWorkout)
    return updatedWorkout
  }

  static startRest(workoutId: string, exerciseId: string, setId: string): WorkoutSession | null {
    const workout = this.getCurrentWorkout()
    if (!workout || workout.id !== workoutId) return null

    const exercise = workout.exercises.find((ex) => ex.id === exerciseId)
    if (!exercise) return null

    const set = exercise.sets.find((s) => s.id === setId)
    if (!set) return null

    set.restStartTime = Date.now()
    this.saveCurrentWorkout(workout)
    return workout
  }

  static completeWorkout(workoutId: string): WorkoutSession | null {
    if (typeof window === "undefined") return null

    try {
      const stored = localStorage.getItem(this.IN_PROGRESS_KEY)
      if (!stored) return null

      const workouts: WorkoutSession[] = JSON.parse(stored)
      const workout = workouts.find((w) => w.id === workoutId)
      if (!workout) return null

      workout.completed = true
      workout.endTime = Date.now()

      // Save to workout history
      this.saveWorkoutToHistory(workout)

      // Remove from in-progress
      if (workout.week && workout.day) {
        this.clearCurrentWorkout(workout.week, workout.day)
      }

      return workout
    } catch (error) {
      console.error("Failed to complete workout:", error)
      return null
    }
  }

  private static saveWorkoutToHistory(workout: WorkoutSession): void {
    if (typeof window === "undefined") return

    try {
      const existing = localStorage.getItem(this.STORAGE_KEY)
      const workouts: WorkoutSession[] = existing ? JSON.parse(existing) : []
      workouts.push(workout)
      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(workouts))
    } catch (error) {
      console.error("Failed to save workout to history:", error)
    }
  }

  static getWorkoutHistory(): WorkoutSession[] {
    if (typeof window === "undefined") return []

    try {
      const stored = localStorage.getItem(this.STORAGE_KEY)
      return stored ? JSON.parse(stored) : []
    } catch {
      return []
    }
  }

  static getCompletedWorkout(week: number, day: number): WorkoutSession | null {
    const history = this.getWorkoutHistory()
    return history.find((workout) => workout.week === week && workout.day === day && workout.completed) || null
  }

  static getWorkout(week: number, day: number): WorkoutSession | null {
    // First check completed workouts in history
    const completed = this.getCompletedWorkout(week, day)
    if (completed) return completed

    // Then check in-progress workouts
    return this.getInProgressWorkout(week, day)
  }

  static hasCompletedWorkout(week: number, day: number): boolean {
    const history = this.getWorkoutHistory()
    return history.some((workout) => workout.week === week && workout.day === day && workout.completed)
  }

  static isWeekCompleted(week: number, daysPerWeek: number): boolean {
    for (let day = 1; day <= daysPerWeek; day++) {
      if (!this.hasCompletedWorkout(week, day)) {
        return false
      }
    }
    return true
  }
}

import { GYM_TEMPLATES, type GymTemplate } from "./gym-templates"
import { WorkoutLogger } from "./workout-logger"

export interface ActiveProgram {
  templateId: string
  template: GymTemplate
  startDate: number
  currentWeek: number
  currentDay: number
  completedWorkouts: number
  totalWorkouts: number
  progress: number
}

export interface ProgramProgress {
  workoutId: string
  date: number
  completed: boolean
  exercises: {
    exerciseId: string
    sets: {
      reps: number
      weight: number
      completed: boolean
    }[]
  }[]
}

export interface ProgramHistoryEntry {
  id: string
  templateId: string
  name: string
  startDate: string
  completionRate: number
  totalWorkouts: number
  completedWorkouts: number
  isActive: boolean
  endDate?: string
}

export class ProgramStateManager {
  private static readonly ACTIVE_PROGRAM_KEY = "liftlog_active_program"
  private static readonly PROGRAM_PROGRESS_KEY = "liftlog_program_progress"
  private static readonly PROGRAM_HISTORY_KEY = "liftlog_program_history"

  static getActiveProgram(): ActiveProgram | null {
    if (typeof window === "undefined") return null

    try {
      const stored = localStorage.getItem(this.ACTIVE_PROGRAM_KEY)
      if (!stored) return null

      const program = JSON.parse(stored) as ActiveProgram

      if (!program.template || !program.template.schedule) {
        const template = GYM_TEMPLATES.find((t) => t.id === program.templateId)
        if (!template) {
          console.error("[v0] Template not found for active program:", program.templateId)
          return null
        }
        program.template = template
        // Save the corrected program back to localStorage
        localStorage.setItem(this.ACTIVE_PROGRAM_KEY, JSON.stringify(program))
      }

      return program
    } catch (error) {
      console.error("[v0] Error loading active program:", error)
      return null
    }
  }

  static setActiveProgram(templateId: string): ActiveProgram | null {
    if (typeof window === "undefined") return null

    const template = GYM_TEMPLATES.find((t) => t.id === templateId)
    if (!template) return null

    // Calculate total workouts in the program
    const daysInSchedule = Object.keys(template.schedule).length
    const totalWorkouts = daysInSchedule * 12 // Assuming 12 weeks for now

    const activeProgram: ActiveProgram = {
      templateId,
      template,
      startDate: Date.now(),
      currentWeek: 1,
      currentDay: 1,
      completedWorkouts: 0,
      totalWorkouts,
      progress: 0,
    }

    localStorage.setItem(this.ACTIVE_PROGRAM_KEY, JSON.stringify(activeProgram))
    console.log("[v0] Set active program:", activeProgram)

    window.dispatchEvent(new Event("programChanged"))

    const history = this.getProgramHistory()
    const newHistoryEntry = {
      id: `program-${Date.now()}`,
      templateId,
      name: template.name,
      startDate: new Date().toISOString(),
      completionRate: 0,
      totalWorkouts,
      completedWorkouts: 0,
      isActive: true,
    }

    // End any currently active program in history
    history.forEach((p) => {
      if (p.isActive) {
        p.isActive = false
        p.endDate = new Date().toISOString()
      }
    })

    history.push(newHistoryEntry)
    localStorage.setItem(this.PROGRAM_HISTORY_KEY, JSON.stringify(history))

    return activeProgram
  }

  static clearActiveProgram(): void {
    if (typeof window === "undefined") return
    localStorage.removeItem(this.ACTIVE_PROGRAM_KEY)
    localStorage.removeItem(this.PROGRAM_PROGRESS_KEY)
    localStorage.removeItem(this.PROGRAM_HISTORY_KEY)
  }

  static getCurrentWorkout(): { name: string; exercises: any[] } | null {
    const activeProgram = this.getActiveProgram()

    if (!activeProgram) {
      return null
    }

    const { template, currentDay } = activeProgram

    const scheduleKeys = Object.keys(template.schedule)

    if (currentDay > scheduleKeys.length) {
      // Reset to first day if we've completed the cycle
      activeProgram.currentDay = 1
      this.saveActiveProgram(activeProgram)
    }

    const dayKey = scheduleKeys[activeProgram.currentDay - 1]

    const workout = template.schedule[dayKey]

    if (!workout) {
      return null
    }

    // Convert gym template format to workout logger format
    const exercises = workout.exercises.map((exercise) => ({
      exerciseId: exercise.exerciseName.toLowerCase().replace(/\s+/g, "-"),
      exerciseName: exercise.exerciseName,
      targetSets: exercise.progressionTemplate.week1?.sets || 3,
      targetReps: exercise.progressionTemplate.week1?.repRange || "8-10",
      targetRest: exercise.restTime,
      muscleGroup: exercise.category,
    }))

    return {
      name: workout.name,
      exercises,
    }
  }

  static completeWorkout(): void {
    const activeProgram = this.getActiveProgram()
    if (!activeProgram) return

    activeProgram.completedWorkouts += 1
    activeProgram.progress = (activeProgram.completedWorkouts / activeProgram.totalWorkouts) * 100

    const scheduleKeys = Object.keys(activeProgram.template.schedule)
    const daysPerWeek = scheduleKeys.length

    // Import WorkoutLogger to check completion status

    // Check if all days in the current week are now completed
    const isCurrentWeekComplete = WorkoutLogger.isWeekCompleted(activeProgram.currentWeek, daysPerWeek)

    if (isCurrentWeekComplete) {
      // All days in current week are done, advance to next week
      activeProgram.currentWeek += 1
      activeProgram.currentDay = 1
      console.log("[v0] Week completed! Advanced to week", activeProgram.currentWeek)
    } else {
      // Find the next incomplete day in the current week
      let nextDay = activeProgram.currentDay
      for (let day = 1; day <= daysPerWeek; day++) {
        if (!WorkoutLogger.hasCompletedWorkout(activeProgram.currentWeek, day)) {
          nextDay = day
          break
        }
      }
      activeProgram.currentDay = nextDay
      console.log("[v0] Advanced to next incomplete day:", nextDay)
    }

    this.saveActiveProgram(activeProgram)

    window.dispatchEvent(new Event("programChanged"))

    const historyEntry = this.getProgramHistory().find((p) => p.isActive)
    if (historyEntry) {
      historyEntry.completedWorkouts = activeProgram.completedWorkouts
      historyEntry.completionRate = activeProgram.progress
      localStorage.setItem(this.PROGRAM_HISTORY_KEY, JSON.stringify(this.getProgramHistory()))
    }

    console.log("[v0] Completed workout, updated progress:", activeProgram)
  }

  static recalculateProgress(): void {
    const activeProgram = this.getActiveProgram()
    if (!activeProgram) return

    const scheduleKeys = Object.keys(activeProgram.template.schedule)
    const daysPerWeek = scheduleKeys.length

    // Find the first incomplete workout
    let foundIncomplete = false
    for (let week = 1; week <= 12; week++) {
      for (let day = 1; day <= daysPerWeek; day++) {
        if (!WorkoutLogger.hasCompletedWorkout(week, day)) {
          activeProgram.currentWeek = week
          activeProgram.currentDay = day
          foundIncomplete = true
          console.log("[v0] Recalculated progress to week", week, "day", day)
          break
        }
      }
      if (foundIncomplete) break
    }

    this.saveActiveProgram(activeProgram)
    window.dispatchEvent(new Event("programChanged"))
  }

  private static saveActiveProgram(program: ActiveProgram): void {
    if (typeof window === "undefined") return
    localStorage.setItem(this.ACTIVE_PROGRAM_KEY, JSON.stringify(program))
  }

  static getProgramProgress(): ProgramProgress[] {
    if (typeof window === "undefined") return []

    try {
      const stored = localStorage.getItem(this.PROGRAM_PROGRESS_KEY)
      return stored ? JSON.parse(stored) : []
    } catch {
      return []
    }
  }

  static addWorkoutProgress(progress: ProgramProgress): void {
    if (typeof window === "undefined") return

    const existing = this.getProgramProgress()
    existing.push(progress)
    localStorage.setItem(this.PROGRAM_PROGRESS_KEY, JSON.stringify(existing))
  }

  private static getProgramHistory(): ProgramHistoryEntry[] {
    if (typeof window === "undefined") return []
    try {
      const history = localStorage.getItem(this.PROGRAM_HISTORY_KEY)
      return history ? JSON.parse(history) : []
    } catch {
      return []
    }
  }

  /**
   * Clean up ghost/duplicate in-progress workouts that have completed versions in history
   * Should be called once on app initialization
   */
  static cleanupGhostWorkouts(): void {
    if (typeof window === "undefined") return

    try {
      const inProgressRaw = localStorage.getItem("liftlog_in_progress_workouts")
      const historyRaw = localStorage.getItem("liftlog_workouts")

      if (!inProgressRaw || !historyRaw) return

      const inProgressWorkouts = JSON.parse(inProgressRaw)
      const historyWorkouts = JSON.parse(historyRaw)

      // Find in-progress workouts that have a completed version in history
      const cleanedInProgress = inProgressWorkouts.filter((inProgress: any) => {
        const hasCompletedVersion = historyWorkouts.some(
          (history: any) =>
            history.week === inProgress.week && history.day === inProgress.day && history.completed,
        )

        // If there's a completed version, check if in-progress is empty
        if (hasCompletedVersion) {
          const isEmpty = inProgress.exercises.every((ex: any) =>
            ex.sets.every((s: any) => s.weight === 0 && s.reps === 0 && !s.completed),
          )

          if (isEmpty) {
            console.log("[v0] Removing empty in-progress workout for week", inProgress.week, "day", inProgress.day)
            return false // Remove this workout
          }
        }

        return true // Keep this workout
      })

      if (cleanedInProgress.length !== inProgressWorkouts.length) {
        localStorage.setItem("liftlog_in_progress_workouts", JSON.stringify(cleanedInProgress))
        console.log(
          "[v0] Cleaned up",
          inProgressWorkouts.length - cleanedInProgress.length,
          "ghost in-progress workouts",
        )
      }
    } catch (error) {
      console.error("[v0] Error cleaning up ghost workouts:", error)
    }
  }
}

