const handleEndProgram = () => {
  if (!workout || endProgramConfirmation !== "End Program") return

  // Mark all incomplete sets as skipped
  const updatedWorkout = { ...workout }
  updatedWorkout.exercises.forEach((exercise) => {
    exercise.sets.forEach((set) => {
      if (!set.completed) {
        set.completed = true
        set.reps = 0
        set.weight = 0
        set.skipped = true
      }
    })
  })

  setWorkout(updatedWorkout)
  WorkoutLogger.saveCurrentWorkout(updatedWorkout)

  // Complete current workout
  const completedWorkout = WorkoutLogger.completeWorkout(updatedWorkout.id)

  // End the entire program early
  ProgramStateManager.endProgramEarly("User ended program")

  if (completedWorkout) {
    setCompletedWorkout(completedWorkout)
    setShowEndProgramDialog(false)
    setShowCompletionDialog(true)
  }

  // Navigate back to train view after completion
  if (onComplete) {
    setTimeout(() => {
      onComplete()
    }, 2000)
  }
}

