          <DialogDescription className={`text-lg font-medium ${getCompletionColor()}`}>
            {getCompletionMessage()}
          </DialogDescription>
        </DialogHeader>

        <ScrollArea className="max-h-[60vh] pr-4">
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
