          <ScrollArea className="max-h-[50vh] pr-4">
            <div className="space-y-4">
              {/* Exercises Summary */}
              <div className="text-center">
                <div className="text-sm text-muted-foreground mb-2">Exercises</div>
                <div className="space-y-1">
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <div className="w-4 h-4 rounded-full bg-green-500 flex items-center justify-center">
                        <span className="text-white text-xs">✓</span>
                      </div>
                      <span>Completed</span>
                    </div>
                    <span className="font-medium">{stats.completedSets}</span>
                  </div>
                  {stats.skippedSets > 0 && (
                    <div className="flex items-center justify-between text-sm">
                      <div className="flex items-center gap-2">
                        <div className="w-4 h-4 rounded-full bg-blue-500 flex items-center justify-center">
                          <span className="text-white text-xs">-</span>
                        </div>
                        <span>Skipped</span>
                      </div>
                      <span className="font-medium">{stats.skippedSets}</span>
                    </div>
                  )}
                </div>
              </div>

              {/* Achievement Badges */}
              {stats.completionRate === 100 && (
                <div className="flex flex-wrap gap-2 justify-center">
                  <Badge className="bg-yellow-100 text-yellow-800 border-yellow-200">Perfect Workout</Badge>
                </div>
              )}
            </div>
          </ScrollArea>

          {/* Footer Buttons */}
          <div className="flex flex-col space-y-2">
            <Button variant="outline" onClick={onViewMuscleGroupStats} className="w-full bg-transparent">
              VIEW MESOCYCLE STATS
            </Button>
            {/* Next Workout Button - Blue color (primary) */}
            {hasNextWorkout() ? (
              <Button onClick={handleNextWorkout} className="w-full bg-primary hover:bg-primary/90 text-primary-foreground">
                NEXT WORKOUT
              </Button>
            ) : (
              <Button onClick={onClose} className="w-full bg-primary hover:bg-primary/90 text-primary-foreground">
                BACK TO DASHBOARD
              </Button>
            )}
          </div>

