"use client"

import { useState, useEffect } from "react"
import * as DialogPrimitive from "@radix-ui/react-dialog"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Trophy, Clock, Target, TrendingUp, Calendar, XIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import type { WorkoutSession } from "@/lib/workout-logger"
import { ProgramStateManager } from "@/lib/program-state"

interface WorkoutCompletionDialogProps {
  workout: WorkoutSession | null
  open: boolean
  onClose: () => void
  onViewMuscleGroupStats: () => void
  onStartNextWorkout?: () => void
}

export function WorkoutCompletionDialog({
  workout,
  open,
  onClose,
  onViewMuscleGroupStats,
  onStartNextWorkout,
}: WorkoutCompletionDialogProps) {
  const [showCelebration, setShowCelebration] = useState(false)

  useEffect(() => {
    if (open && workout) {
      setShowCelebration(true)
      const timer = setTimeout(() => setShowCelebration(false), 2000)
      return () => clearTimeout(timer)
    }
  }, [open, workout])

  if (!workout) return null

  const getWorkoutStats = () => {
    let totalSets = 0
    let completedSets = 0
    let skippedSets = 0
    let totalVolume = 0
    let totalReps = 0

    workout.exercises.forEach((exercise) => {
      exercise.sets.forEach((set) => {
        totalSets++
        if (set.completed) {
          if (set.reps === 0 && set.weight === 0) {
            skippedSets++
          } else {
            completedSets++
            totalVolume += set.weight * set.reps
            totalReps += set.reps
          }
        }
      })
    })

    const duration = workout.endTime ? Math.floor((workout.endTime - workout.startTime) / 1000 / 60) : 0
    const completionRate = totalSets > 0 ? Math.round((completedSets / totalSets) * 100) : 0

    return {
      totalSets,
      completedSets,
      skippedSets,
      totalVolume,
      totalReps,
      duration,
      completionRate,
      exercises: workout.exercises.length,
    }
  }

  const stats = getWorkoutStats()

  const getCompletionMessage = () => {
    if (stats.completionRate >= 90) return "Outstanding workout! 🔥"
    if (stats.completionRate >= 75) return "Great job! 💪"
    if (stats.completionRate >= 50) return "Good effort! 👍"
    return "Every workout counts! 💯"
  }

  const getCompletionColor = () => {
    if (stats.completionRate >= 90) return "text-green-600"
    if (stats.completionRate >= 75) return "text-blue-600"
    if (stats.completionRate >= 50) return "text-orange-600"
    return "text-purple-600"
  }

  const handleNextWorkout = () => {
    // The program state is now updated in page.tsx's handleWorkoutComplete

    // Close dialog and start next workout
    onClose()
    onStartNextWorkout?.()
  }

  const hasNextWorkout = () => {
    const activeProgram = ProgramStateManager.getActiveProgram()
    if (!activeProgram) return false

    // Check if we haven't completed all workouts yet
    return activeProgram.completedWorkouts < activeProgram.totalWorkouts
  }

  return (
    <DialogPrimitive.Root open={open} onOpenChange={onClose}>
      <DialogPrimitive.Portal>
        {/* Lighter overlay (20% opacity) to keep background workout visible */}
        <DialogPrimitive.Overlay className="fixed inset-0 z-50 bg-black/20 backdrop-blur-[2px] data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />

        {/* Dialog Content */}
        <DialogPrimitive.Content
          className={cn(
            "fixed top-[50%] left-[50%] z-50 grid w-full max-w-md translate-x-[-50%] translate-y-[-50%] gap-4 rounded-lg border bg-background p-6 shadow-lg duration-200",
            "data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95"
          )}
        >
          {/* Close Button */}
          <DialogPrimitive.Close className="absolute top-4 right-4 rounded-xs opacity-70 transition-opacity hover:opacity-100 focus:ring-2 focus:ring-offset-2 focus:outline-hidden

"use client"

import { useState, useEffect } from "react"
import * as DialogPrimitive from "@radix-ui/react-dialog"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Trophy, Clock, Target, TrendingUp, Calendar, XIcon } from "lucide-react"
import { cn } from "@/lib/utils"
import type { WorkoutSession } from "@/lib/workout-logger"
import { ProgramStateManager } from "@/lib/program-state"

interface WorkoutCompletionDialogProps {
  workout: WorkoutSession | null
  open: boolean
  onClose: () => void
  onViewMuscleGroupStats: () => void
  onStartNextWorkout?: () => void
}

export function WorkoutCompletionDialog({
  workout,
  open,
  onClose,
  onViewMuscleGroupStats,
  onStartNextWorkout,
}: WorkoutCompletionDialogProps) {
  const [showCelebration, setShowCelebration] = useState(false)

  useEffect(() => {
    if (open && workout) {
      setShowCelebration(true)
      const timer = setTimeout(() => setShowCelebration(false), 2000)
      return () => clearTimeout(timer)
    }
  }, [open, workout])

  if (!workout) return null

  const getWorkoutStats = () => {
    let totalSets = 0
    let completedSets = 0
    let skippedSets = 0
    let totalVolume = 0
    let totalReps = 0

    workout.exercises.forEach((exercise) => {
      exercise.sets.forEach((set) => {
        totalSets++
        if (set.completed) {
          if (set.reps === 0 && set.weight === 0) {
            skippedSets++
          } else {
            completedSets++
            totalVolume += set.weight * set.reps
            totalReps += set.reps
          }
        }
      })
    })

    const duration = workout.endTime ? Math.floor((workout.endTime - workout.startTime) / 1000 / 60) : 0
    const completionRate = totalSets > 0 ? Math.round((completedSets / totalSets) * 100) : 0

    return {
      totalSets,
      completedSets,
      skippedSets,
      totalVolume,
      totalReps,
      duration,
      completionRate,
      exercises: workout.exercises.length,
    }
  }

  const stats = getWorkoutStats()

  const getCompletionMessage = () => {
    if (stats.completionRate >= 90) return "Advancing through your meso"
    if (stats.completionRate >= 75) return "Great job! 💪"
    if (stats.completionRate >= 50) return "Good effort! 👍"
    return "Every workout counts! 💯"
  }

  const getCompletionColor = () => {
    if (stats.completionRate >= 90) return "text-muted-foreground"
    if (stats.completionRate >= 75) return "text-blue-600"
    if (stats.completionRate >= 50) return "text-orange-600"
    return "text-purple-600"
  }

  const handleNextWorkout = () => {
    // The program state is now updated in page.tsx's handleWorkoutComplete

    // Close dialog and start next workout
    onClose()
    onStartNextWorkout?.()
  }

  const hasNextWorkout = () => {
    const activeProgram = ProgramStateManager.getActiveProgram()
    if (!activeProgram) return false

    // Check if we haven't completed all workouts yet
    return activeProgram.completedWorkouts < activeProgram.totalWorkouts
  }

  return (
    <DialogPrimitive.Root open={open} onOpenChange={onClose}>
      <DialogPrimitive.Portal>
        {/* Lighter overlay (20% opacity) to keep background workout visible */}
        <DialogPrimitive.Overlay className="fixed inset-0 z-50 bg-black/20 backdrop-blur-[2px] data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0" />

        {/* Dialog Content */}
        <DialogPrimitive.Content
          className={cn(
            "fixed top-[50%] left-[50%] z-50 grid w-full max-w-md translate-x-[-50%] translate-y-[-50%] gap-4 rounded-lg border bg-background p-6 shadow-lg duration-200",
            "data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 max-w-[calc(100%-2rem)]"
          )}
        >
          {/* Close Button */}
          <DialogPrimitive.Close className="absolute top-4 right-4 rounded-xs opacity-70 transition-opacity hover:opacity-100 focus:ring-2 focus:ring-offset-2 focus:outline-hidden">
            <XIcon className="h-4 w-4" />
            <span className="sr-only">Close</span>
          </DialogPrimitive.Close>

          {/* Header */}
          <div className="text-center">
            <div className="mx-auto mb-4">
              {showCelebration ? (
                <div className="animate-bounce">
                  <Trophy className="h-16 w-16 text-yellow-500 mx-auto" />
                </div>
              ) : (
                <Trophy className="h-16 w-16 text-yellow-500 mx-auto" />
              )}
            </div>
            <DialogPrimitive.Title className="text-2xl font-semibold">
              Workout complete!
            </DialogPrimitive.Title>
            <DialogPrimitive.Description className={`text-base font-normal mt-2 ${getCompletionColor()}`}>
              {getCompletionMessage()}
            </DialogPrimitive.Description>
            {stats.completionRate >= 90 && (
              <p className="text-sm text-muted-foreground mt-2">
                Now it's time to focus on as much rest and relaxation as you can get so that you grow as much muscle as
                possible before your next workout! Rest well!
              </p>
            )}
          </div>

          {/* Stats Section */}
          <ScrollArea className="max-h-[50vh] pr-4">
            <div className="space-y-4">
              {/* Exercises Summary */}
              <div className="text-center">
                <div className="text-sm text-muted-foreground mb-2">Exercises</div>
                <div className="space-y-1">
                  <div className="flex items-center justify-between text-sm">
                    <div className="flex items-center gap-2">
                      <div className="w-4 h-4 rounded-full bg-green-500 flex items-center justify-center">
                        <span className="text-white text-xs">✓</span>
                      </div>
                      <span>Completed</span>
                    </div>
                    <span className="font-medium">{stats.completedSets}</span>
                  </div>
                  {stats.skippedSets > 0 && (
                    <div className="flex items-center justify-between text-sm">
                      <div className="flex items-center gap-2">
                        <div className="w-4 h-4 rounded-full bg-blue-500 flex items-center justify-center">
                          <span className="text-white text-xs">-</span>
                        </div>
                        <span>Skipped</span>
                      </div>
                      <span className="font-medium">{stats.skippedSets}</span>
                    </div>
                  )}
                </div>
              </div>

              {/* Achievement Badges */}
              {stats.completionRate === 100 && (
                <div className="flex flex-wrap gap-2 justify-center">
                  <Badge className="bg-yellow-100 text-yellow-800 border-yellow-200">Perfect Workout</Badge>
                </div>
              )}
            </div>
          </ScrollArea>

          {/* Footer Buttons */}
          <div className="flex flex-col space-y-2">
            <Button variant="outline" onClick={onViewMuscleGroupStats} className="w-full bg-transparent">
              VIEW MESOCYCLE STATS
            </Button>
            {/* Next Workout Button - Blue color (primary) */}
            {hasNextWorkout() ? (
              <Button onClick={handleNextWorkout} className="w-full bg-primary hover:bg-primary/90 text-primary-foreground">
                NEXT WORKOUT
              </Button>
            ) : (
              <Button onClick={onClose} className="w-full bg-primary hover:bg-primary/90 text-primary-foreground">
                BACK TO DASHBOARD
              </Button>
            )}
          </div>
